1	'use server'
2	import { revalidatePath } from 'next/cache'
3	import { prisma } from '@/lib/prisma'
4	import { requireAdmin } from '@/lib/auth'
5	import { wordSaveSchema } from './schema'
6	import type { ActionResult } from '@/lib/errors'
7	
8	export async function createWord(input: unknown): Promise<ActionResult<{ id: number }>> {
9	    await requireAdmin()
10	    const parsed = wordSaveSchema.safeParse(input)
11	    if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
12	
13	    let word: { id: number }
14	    try {
15	        word = await prisma.word.create({ data: parsed.data })
16	    } catch {
17	        return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
18	    }
19	    revalidatePath('/word')
20	    return { success: true, data: { id: word.id } }
21	}
22	
23	export async function updateWord(id: number, input: unknown): Promise<ActionResult> {
24	    await requireAdmin()
25	    const parsed = wordSaveSchema.safeParse(input)
26	    if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
27	
28	    try {
29	        await prisma.word.update({ where: { id }, data: parsed.data })
30	    } catch {
31	        return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
32	    }
33	    revalidatePath('/word')
34	    return { success: true, data: undefined }
35	}
36	
37	export async function deleteWord(id: number): Promise<ActionResult> {
38	    await requireAdmin()
39	    try {
40	        await prisma.word.delete({ where: { id } })
41	    } catch {
42	        return { success: false, error: '삭제 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
43	    }
44	    revalidatePath('/word')
45	    return { success: true, data: undefined }
46	}
